namespace sv_4718599070c843e28b14d153f63b1ace.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@rendermode InteractiveServer
@using sv_4718599070c843e28b14d153f63b1ace.Services
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-container">
    <aside class="catalog-sidebar">
        <h3>Filters</h3>

        <div class="filter-section">
            <h4>Categories</h4>
            @if (categories is not null)
            {
                @foreach (var category in categories)
                {
                    <label class="filter-checkbox">
                        <input type="checkbox"
                               checked="@selectedCategories.Contains(category)"
                               @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                        @category
                    </label>
                }
            }
        </div>

        <div class="filter-section">
            <h4>Price Range</h4>
            <label>
                Min:
                <input type="number" step="0.01" min="0" @bind="minPrice" />
            </label>
            <label>
                Max:
                <input type="number" step="0.01" min="0" @bind="maxPrice" />
            </label>
        </div>

        <div class="filter-section">
            <label class="filter-checkbox">
                <input type="checkbox" @bind="inStockOnly" />
                In Stock Only
            </label>
        </div>

        <div class="filter-actions">
            <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn btn-secondary" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    <main class="catalog-main">
        @if (isLoading)
        {
            <div class="catalog-loading">
                <p>Loading products...</p>
            </div>
        }
        else if (errorMessage is not null)
        {
            <div class="catalog-error">
                <p>Error: @errorMessage</p>
                <button class="btn btn-primary" @onclick="LoadProducts">Retry</button>
            </div>
        }
        else if (searchResult is null || searchResult.Items.Count == 0)
        {
            <div class="catalog-empty">
                <p>No products found matching your criteria.</p>
            </div>
        }
        else
        {
            <div class="catalog-toolbar">
                <div class="sort-control">
                    <label>Sort by:</label>
                    <select @bind="sortBy" @bind:after="LoadProducts">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="showing-label">
                    Showing @(((searchResult.Page - 1) * searchResult.PageSize) + 1)–@(Math.Min(searchResult.Page * searchResult.PageSize, searchResult.TotalCount)) of @searchResult.TotalCount products
                </span>
            </div>

            <div class="product-grid">
                @foreach (var product in searchResult.Items)
                {
                    <div class="product-card" @onclick="() => OnProductSelected(product)">
                        <div class="product-image" title="@product.Name">
                            <span>@product.Name</span>
                        </div>
                        <div class="product-info">
                            <h4 class="product-name">@product.Name</h4>
                            <p class="product-price">@product.Price.ToString("C")</p>
                            <p class="product-rating">@GetStarRating(product.Rating)</p>
                            @if (!product.InStock)
                            {
                                <span class="badge-out-of-stock">Out of Stock</span>
                            }
                            <button class="btn btn-add-to-cart"
                                    disabled="@(!product.InStock)"
                                    @onclick="() => AddToCart(product)"
                                    @onclick:stopPropagation="true">
                                Add to Cart
                            </button>
                        </div>
                    </div>
                }
            </div>

            <div class="pagination">
                <button class="btn btn-page" disabled="@(currentPage <= 1)" @onclick="PreviousPage">Previous</button>
                @for (int i = 1; i <= totalPages; i++)
                {
                    var pageNum = i;
                    <button class="btn btn-page @(pageNum == currentPage ? "active" : "")"
                            @onclick="() => GoToPage(pageNum)">
                        @pageNum
                    </button>
                }
                <button class="btn btn-page" disabled="@(currentPage >= totalPages)" @onclick="NextPage">Next</button>
            </div>
        }
    </main>
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductClick { get; set; }

    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private int pageSize = 12;
    private int totalPages;
    private bool isLoading;
    private string? errorMessage;
    private PagedResult<Product>? searchResult;

    protected override async Task OnInitializedAsync()
    {
        await LoadCategories();
        await LoadProducts();
    }

    private async Task LoadCategories()
    {
        try
        {
            categories = await ProductService.GetCategoriesAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task LoadProducts()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            searchResult = await ProductService.SearchAsync(filter, sortBy, currentPage, pageSize);
            totalPages = (int)Math.Ceiling((double)searchResult.TotalCount / pageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
            searchResult = null;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        currentPage = page;
        await LoadProducts();
    }

    private async Task PreviousPage()
    {
        if (currentPage > 1)
        {
            currentPage--;
            await LoadProducts();
        }
    }

    private async Task NextPage()
    {
        if (currentPage < totalPages)
        {
            currentPage++;
            await LoadProducts();
        }
    }

    private async Task OnProductSelected(Product product)
    {
        if (OnProductClick.HasDelegate)
        {
            await OnProductClick.InvokeAsync(product);
        }
    }

    private Task AddToCart(Product product)
    {
        // Placeholder for add to cart logic
        return Task.CompletedTask;
    }

    private string GetStarRating(double rating)
    {
        int fullStars = (int)Math.Round(rating);
        int emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }
}

.catalog-container {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
}

.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    padding: 1rem;
    border-right: 1px solid #e0e0e0;
}

.catalog-sidebar h3 {
    margin-top: 0;
}

.catalog-main {
    width: 75%;
    flex: 1;
}

.filter-section {
    margin-bottom: 1.5rem;
}

.filter-section h4 {
    margin-bottom: 0.5rem;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    margin-bottom: 0.3rem;
    cursor: pointer;
}

.filter-section input[type="number"] {
    width: 100%;
    padding: 0.3rem;
    margin-top: 0.25rem;
    box-sizing: border-box;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.btn {
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.btn-primary {
    background-color: #0d6efd;
    color: white;
}

.btn-primary:hover:not(:disabled) {
    background-color: #0b5ed7;
}

.btn-secondary {
    background-color: #6c757d;
    color: white;
}

.btn-secondary:hover:not(:disabled) {
    background-color: #5c636a;
}

.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    padding: 0.75rem;
    background: #f8f9fa;
    border-radius: 4px;
}

.sort-control {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.sort-control select {
    padding: 0.3rem 0.5rem;
}

.showing-label {
    font-size: 0.9rem;
    color: #666;
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1rem;
}

.product-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    overflow: hidden;
    cursor: pointer;
    transition: box-shadow 0.2s;
}

.product-card:hover {
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
}

.product-image {
    height: 150px;
    background: #f0f0f0;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 0.85rem;
    text-align: center;
    padding: 0.5rem;
}

.product-info {
    padding: 0.75rem;
}

.product-name {
    margin: 0 0 0.4rem;
    font-size: 1rem;
}

.product-price {
    margin: 0 0 0.3rem;
    font-weight: bold;
    color: #2e7d32;
}

.product-rating {
    margin: 0 0 0.4rem;
    color: #f9a825;
}

.badge-out-of-stock {
    display: inline-block;
    background: #dc3545;
    color: white;
    padding: 0.2rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    margin-bottom: 0.4rem;
}

.btn-add-to-cart {
    width: 100%;
    background-color: #198754;
    color: white;
    margin-top: 0.5rem;
}

.btn-add-to-cart:hover:not(:disabled) {
    background-color: #157347;
}

.pagination {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 0.3rem;
    margin-top: 1.5rem;
    padding: 1rem 0;
}

.btn-page {
    background: #fff;
    border: 1px solid #dee2e6;
    color: #0d6efd;
    min-width: 2.2rem;
}

.btn-page:hover:not(:disabled) {
    background: #e9ecef;
}

.btn-page.active {
    background-color: #0d6efd;
    color: white;
    border-color: #0d6efd;
}

.catalog-loading,
.catalog-error,
.catalog-empty {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 300px;
    text-align: center;
}

.catalog-error {
    color: #dc3545;
}

