toolArgs.file_text:
.catalog-container {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
}

.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    padding: 1rem;
    border-right: 1px solid #e0e0e0;
}

.catalog-sidebar h3 {
    margin-top: 0;
}

.catalog-main {
    width: 75%;
    flex: 1;
}

.filter-section {
    margin-bottom: 1.5rem;
}

.filter-section h4 {
    margin-bottom: 0.5rem;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    margin-bottom: 0.3rem;
    cursor: pointer;
}

.filter-section input[type="number"] {
    width: 100%;
    padding: 0.3rem;
    margin-top: 0.25rem;
    box-sizing: border-box;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.btn {
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.btn-primary {
    background-color: #0d6efd;
    color: white;
}

.btn-primary:hover:not(:disabled) {
    background-color: #0b5ed7;
}

.btn-secondary {
    background-color: #6c757d;
    color: white;
}

.btn-secondary:hover:not(:disabled) {
    background-color: #5c636a;
}

.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    padding: 0.75rem;
    background: #f8f9fa;
    border-radius: 4px;
}

.sort-control {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.sort-control select {
    padding: 0.3rem 0.5rem;
}

.showing-label {
    font-size: 0.9rem;
    color: #666;
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1rem;
}

.product-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    overflow: hidden;
    cursor: pointer;
    transition: box-shadow 0.2s;
}

.product-card:hover {
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
}

.product-image {
    height: 150px;
    background: #f0f0f0;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 0.85rem;
    text-align: center;
    padding: 0.5rem;
}

.product-info {
    padding: 0.75rem;
}

.product-name {
    margin: 0 0 0.4rem;
    font-size: 1rem;
}

.product-price {
    margin: 0 0 0.3rem;
    font-weight: bold;
    color: #2e7d32;
}

.product-rating {
    margin: 0 0 0.4rem;
    color: #f9a825;
}

.badge-out-of-stock {
    display: inline-block;
    background: #dc3545;
    color: white;
    padding: 0.2rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    margin-bottom: 0.4rem;
}

.btn-add-to-cart {
    width: 100%;
    background-color: #198754;
    color: white;
    margin-top: 0.5rem;
}

.btn-add-to-cart:hover:not(:disabled) {
    background-color: #157347;
}

.pagination {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 0.3rem;
    margin-top: 1.5rem;
    padding: 1rem 0;
}

.btn-page {
    background: #fff;
    border: 1px solid #dee2e6;
    color: #0d6efd;
    min-width: 2.2rem;
}

.btn-page:hover:not(:disabled) {
    background: #e9ecef;
}

.btn-page.active {
    background-color: #0d6efd;
    color: white;
    border-color: #0d6efd;
}

.catalog-loading,
.catalog-error,
.catalog-empty {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 300px;
    text-align: center;
}

.catalog-error {
    color: #dc3545;
